				if (fe_suaf) return;

//Calculo de la cantidad de familiares a cargo
//1- en ax_otrosfamaf guarda la cantidad de familiares a cargo que no cuentan como hijos
//2- en ax_hijosaf guarda la cantidad de hijos a cargo de las asignaciones.
//3- en ax_hijosdaf guarda la cantidad de hijos discapacitados a cargo de las asignaciones.
//4- en vs_hijohig guarda el importe por la cantidad de hijos a cargo de Impuesto a la Ganancia
//5- en vs_hijoig guarda la cantidad de hijos a cargo de Impuesto a la Ganancia
//6- en ax_ayudahijosaf guardo la cantidad de hijos para los cuales cobrara ayuda escolar
//7- en ax_ayudahijosdaf guardo la cantidad de hijos discapacitados para los cuales cobrara ayuda escolar

ax_hijosaf = 0;
ax_hijosdaf = 0;
ax_otrosfamaf = 0;
ax_ayudahijosdaf = 0;
ax_ayudahijosaf = 0;
int edad; 
//La edad se obtiene a partir de la fecha de nacimiento y la fecha de liquidacion
double importe;

//Obtiene el importe para del idig para el año y mes de la fecha de pago
importe = Adic.ImporteIDIG(Liquidacion.FechaPago.Year, Liquidacion.FechaPago.Month, "2");

foreach(NucleusRH.Base.Liquidacion.LegajoEmpresaDDO.FAMILIAR_PER_DDO familiar in Legajo.Familiares) 
{
  //Setear variables Propiedades del Familiar
  edad = DiffYears(familiar.FechaNacimiento, LastDateMonth(Date(1, Liquidacion.Fecha.Month, Liquidacion.Fecha.Year)).AddMonths(-1));
  if (familiar.Vive) 
  {
    // CALCULOS RELACIONADOS A HIJOS           
    //2               Hijo
    //3               Hija
    //18              Hijastra
    //19              Hijastro
    if(familiar.TipoFamiliar == "2" || familiar.TipoFamiliar == "3" ||  
       familiar.TipoFamiliar == "18" || familiar.TipoFamiliar == "19") 
    {
      if (familiar.ACargoAsignacionFamiliar && !familiar.Discapacidad && (edad < 18)) 
      {
        ax_hijosaf = ax_hijosaf + 1;
        if (((familiar.NivelEscolaridad == "1") ||(familiar.NivelEscolaridad == "2")||
            (familiar.NivelEscolaridad == "3") ||(familiar.NivelEscolaridad == "6"))&&
            (edad < 18))
        {
          ax_ayudahijosaf = ax_ayudahijosaf + 1;
        }
      }

      if (familiar.ACargoAsignacionFamiliar && familiar.Discapacidad)
      {
        ax_hijosdaf = ax_hijosdaf + 1;
        if (((familiar.NivelEscolaridad == "1") ||(familiar.NivelEscolaridad == "2")||
            (familiar.NivelEscolaridad == "3") ||(familiar.NivelEscolaridad == "4")||
            (familiar.NivelEscolaridad == "5") ||(familiar.NivelEscolaridad == "6")) &&
            (edad < 18))
        {
          ax_ayudahijosdaf = ax_ayudahijosdaf + 1;
        }
      }

      if (familiar.ACargoIG && (familiar.FechaHastaIGNull || familiar.FechaHastaIG > Liquidacion.FechaPago)) 
      {
        vs_hijoig++;
      }            

      if (familiar.FechaHastaIGNull || familiar.FechaHastaIG <= Liquidacion.FechaPago) 
      {
        if (familiar.FechaDesdeIG >= Liquidacion.FechaPago) 
          {
            vs_hijohig = vs_hijohig + importe;
          }
      }


    } else 
      {
        if (familiar.ACargoAsignacionFamiliar) 
        {
          ax_otrosfamaf = ax_otrosfamaf + 1;
        }
      }

   }
}

