arrRevistas.Add("01:" + dteFecha.Day.ToString()); //(TipoLic:Dia)

//Recorre las licencias para el período actual
foreach(NucleusRH.Base.Liquidacion.LegajoEmpresaDDO.LICEN_PER_DDO licencia in Adic.ObtenerLicencias(Liquidacion.Periodo)) {
    //Warning(" Licencia: " + licencia.CodSIJP.ToString() + ":" + licencia.FechaInicio.ToString());
    if (licencia.CodSIJP == null || licencia.CodSIJP == "9999") continue;
    intContador++;

    if (intContador == 1) {
        if (licencia.FechaInicio <= dteFecha) {                                              
            arrRevistas[arrRevistas.Count - 1] = licencia.CodSIJP + ":1";
        } else {                                                                                  
            arrRevistas.Add(licencia.CodSIJP + ":" + licencia.FechaInicio.Day.ToString());
        }

    } else {
        if (licencia.FechaInicio.Date == dteFecha.Date) 
        {   //Agrega la situacion de la licencia            
            if (((string) arrRevistas[arrRevistas.Count - 1]).Split(':')[0] != licencia.CodSIJP)
              arrRevistas.Add(licencia.CodSIJP + ":" + licencia.FechaInicio.Day.ToString());
        } else {
            //Agrega una situacion de activo y después la de la licencia            
            arrRevistas.Add("01:" + dteFecha.Day.ToString());            
            arrRevistas.Add(licencia.CodSIJP + ":" + licencia.FechaInicio.Day.ToString());
        }
    }    
    dteFecha = licencia.FechaFin.AddDays(1d);
    if (arrRevistas.Count >= 3) //La lista debe venir ordenada
        break;
}

