         SST = Round(vs_totsret,2) - Round(vs_totsac,2) - Round(vs_afipvacaciones,2);
         SSTCN = Round(vs_totsret,2) - Round(vs_totsac,2) - Round(vs_afipvacaciones,2) + Round(ax_noremcondesc,2);
