			double Tope = 0d;
double TopeOS = 0d;
double TopeSAC = 0d;
double TopeOSSAC = 0d;

if (Liquidacion.Periodo == 200901 || Liquidacion.Periodo == 200902) Tope = 7800;
if (Liquidacion.Periodo > 200902 && Liquidacion.Periodo < 200909) Tope = 8711.82;
if (Liquidacion.Periodo >= 200909) Tope = 9351.30;
TopeSAC = Tope/2; 

if (Liquidacion.Periodo == 200901 || Liquidacion.Periodo == 200902||Liquidacion.Periodo == 200903) TopeOS = 7800;
if (Liquidacion.Periodo > 200903 && Liquidacion.Periodo < 200909) TopeOS = 8711.82;
if (Liquidacion.Periodo >= 200909) TopeOS = 9351.30;
TopeOSSAC = TopeOS/2;

// tope de vacaciones
int mes = Liquidacion.Periodo %100;
int cant = 30;
if (mes==1 && ax_cantVacaMes01!=0) cant = (30 - ax_cantVacaMes01) + ax_cantVacaMesActual;
if (mes==2 && ax_cantVacaMes02!=0) cant = (30 - ax_cantVacaMes02) + ax_cantVacaMesActual;
if (mes==3 && ax_cantVacaMes03!=0) cant = (30 - ax_cantVacaMes03) + ax_cantVacaMesActual;
if (mes==4 && ax_cantVacaMes04!=0) cant = (30 - ax_cantVacaMes04) + ax_cantVacaMesActual;
if (mes==5 && ax_cantVacaMes05!=0) cant = (30 - ax_cantVacaMes05) + ax_cantVacaMesActual;                                                                                       
if (mes==6 && ax_cantVacaMes06!=0) cant = (30 - ax_cantVacaMes06) + ax_cantVacaMesActual;
if (mes==7 && ax_cantVacaMes07!=0) cant = (30 - ax_cantVacaMes07) + ax_cantVacaMesActual;
if (mes==8 && ax_cantVacaMes08!=0) cant = (30 - ax_cantVacaMes08) + ax_cantVacaMesActual;
if (mes==9 && ax_cantVacaMes09!=0) cant = (30 - ax_cantVacaMes09) + ax_cantVacaMesActual;                                                                                       
if (mes==10 && ax_cantVacaMes10!=0) cant = (30 - ax_cantVacaMes10) + ax_cantVacaMesActual;
if (mes==11 && ax_cantVacaMes11!=0) cant = (30 - ax_cantVacaMes11) + ax_cantVacaMesActual;
if (mes==12 && ax_cantVacaMes12!=0) cant = (30 - ax_cantVacaMes12) + ax_cantVacaMesActual; 

Tope = Tope / 30 * cant;  
TopeOS = TopeOS / 30 * cant;

//ap_totsretperiodo Acumula el total sujeto a retencion del periodo
//np_totsretpluriempleo El total sujeto a retencion de otras liquidaciones.
Tope = Tope - ap_totsretperiodo - np_totsretpluriempleo;
if (Tope<0) Tope = 0;
TopeSAC = TopeSAC - ap_totSacPeriodo - np_totsacpluriempleo;
if (TopeSAC<0) TopeSAC = 0;
TopeOS = TopeOS - ap_totsretperiodo - np_totsretpluriempleo;   
if (TopeOS<0) TopeOS = 0;
TopeOSSAC = TopeOSSAC - ap_totSacPeriodo - np_totsacpluriempleo;
if (TopeOSSAC<0) TopeOSSAC = 0;

if (Tope < 0) Tope = 0;
if (TopeOS < 0) TopeOS = 0;

double BaseSueldo = vs_totsret - vs_totsac;
if (BaseSueldo > Tope)    
  BaseSueldo = Tope;

double BaseSAC = vs_totsac;
if (vs_totsac > TopeSAC)
  BaseSAC = TopeSAC; 

double BaseSueldoMasNoRem = BaseSueldo + ax_noremcondesc;
if (BaseSueldoMasNoRem > Tope)    
  BaseSueldoMasNoRem = Tope;

/* SINDICATOS */
//ax_basesind - Guarda el Base para sindicatos
ax_basesind = BaseSueldoMasNoRem + BaseSAC;
ax_basesindsintope = vs_totsret + ax_noremcondesc;

/* OBRAS SOCIALES */
//ax_baseos - Guarda el Base para os
ax_baseos = vs_totsret - vs_totsac + ax_noremcondesc;
if (ax_baseos > TopeOS)    
  ax_baseos = TopeOS;
if (vs_totsac > TopeOSSAC) 
  ax_baseos += TopeOSSAC;                           
else
  ax_baseos += vs_totsac;                           
ax_baseossintope = vs_totsret + ax_noremcondesc;

/* SEGURO DE VIDA COLECTIVO */
ax_baseseguro = BaseSueldo + BaseSAC;
ax_basesegurosintope = vs_totsret;

/* AFJP */ 
ax_basjubi = BaseSueldo + BaseSAC;
ax_basjubisintope = vs_totsret;


/* ART Variable */
if (Legajo.TipoPersonal == "3" || fp_modContracion == 10) //Si es pasante
  ax_baseart = vs_totnsret;
else
  ax_baseart = BaseSueldo;

if (ax_baseart > Tope)    
  ax_baseart = Tope;

if (vs_totsac > TopeSAC) //si se pago sac
  ax_baseart += TopeSAC; 
else
  ax_baseart +=  vs_totsac;



